import java.sql.*;   // We need this package because we're going to use a Connection object, Statement etc...       
public class java_50813_JDBCQueryHandler_A03 {   
     public static void main(String[] args) throws SQLException{     
          String url = "jdbc:mysql://localhost/test";  // MySQL database connection string  
          String username="username";               // Database Username      
          String password="password";              // Password for the user    	        		   
           Connection con;                          // This will be used to connect with DB       	 	     			            	   									     	       								 “Connections are thread safe and it maintains a pool of connections, which can serve multiple threads at once.”      							   "A connection in Java is called as: In JDBC (Java Database Connectivity), we create new Connections using DriverManager class."
           Statement stmt;                         // This will be used to run SQL statements   	        		           									 “Statements are also thread safe, and a single statement can perform multiple operations.”      							   "In JDBC connection is established through the above Connection object by calling methods such as getConnection(), createStatement()."
           ResultSet rs;                           // This will be used to retrieve data from DB   	        		           									 “ResultSets are mainly for fetching large amounts of database records.”      							   "In JDBC, the result set is iterated using a while loop."    			            
           DriverManager driverManager;          // We'll be going ahead and creating this object to get our MySQL jdbc drivers   	        		           									 “Driver Manager of Java Database Connectivity (JDBC) allows us access DB’s JAR File.”      							   "In the above code, Drivermanager class has a method called 'getConnection()' which takes two parameters like url and credentials."
           // Creating connection object to connect with MySQL database     	        		           									 “To create Connection we need URL of DB (Database) , Username & Password.”      							   "We do this by using driverManager class method 'getConnection()' which takes two parameters like url and credentials."
           con = DriverManager.getConnection(url,username,password);     // Creating connection to the database     	        		           									 “Creates a new Connection with JDBC from given URL & Credentials”      							   "We use this 'con' object in our sql statement and operations."
           System.out.println("Connection Created Successfully!");        // Printing message on console     	        		           									 “Prints the Message to Console - Connection created successfully!…"                                                                                                       								                   			                             "Message will be printed only when connection is successful, otherwise an exception occurs."      
           stmt = con.createStatement();                                // Creates a new statement object for DB operations     	        		           									 “Creating Statement from the Connection”                                                    	"A PreparedStatements are thread safe and can perform multiple SQL statements at once while JDBC has prepared all these in advance."
           String sql = "INSERT INTO Users (Id, Name) VALUES(1,'Test')";   // Our Simple insert query string.     	        		           									 “A simple select Query”      								"In this example we’re using a PreparedStatement object that has been prepared and all parameters are set before it's executed."
           stmt.executeUpdate(sql);                                    // Execute the SQL statement       			                                                                 "Executes update operation on database by calling execute method in Statement class"      							   “If we have more than one parameter, they must be passed as separate arguments to this methods”    			"This is how you would pass multiple parameters."
           rs = stmt.executeQuery("SELECT * FROM Users");              // Execute a simple Query     	        		           									    "A select query execution using statement object"      							   “If we have more than one parameter, they must be passed as separate arguments to this methods”    				"This is how you would pass multiple parameters."
           while (rs.next()) {                                        // Retrieving Data     	        		           									    "A loop that retrieves data from database"      							   “If we have more than one parameter, they must be passed as separate arguments to this methods”    				"This is how you would pass multiple parameters."
               String name = rs.getString("Name");                     // Accessing Data using Column Name     	        		           									    "Access Database data column through the ResultSet object"      							   “If we have more than one parameter, they must be passed as separate arguments to this methods”    				"This is how you would pass multiple parameters."
               System.out.println("Name: " + name);                    // Printing Data on console     	        		           									    "-"      							   “If we have more than one parameter, they must be passed as separate arguments to this methods”    				"This is how you would pass multiple parameters."
           }                                                         	// Here the database operations are performed using JDBC. In real life example when any exception occurs while executing queries it will handle in try-catch block or else clause of program which ensures that we don’t crash our application if something goes wrong with query execution, instead gracefully handling those scenarios and showing user friendly message to them about what went wrong along the way."
     }  // End main method   	        		           										"Ends Main Method in Java"      							   "This is how you would end your program. A typical use of 'Main' function for a java application can be done as mentioned above at last, after all initialization and execution blocks are completed."
}  // End class JDBCQueryHandler   	        		           										"Ends Class in Java"      							   "This is how you would end your program. A typical use of 'Main' function for a java application can be done as mentioned above at last, after all initialization and execution blocks are completed."